I asked for fastbinary to be used because this is how the generated code looks for `read/write`:

    def write(self, oprot):
      if oprot.__class__ == TBinaryProtocol.TBinaryProtocolAccelerated and self.thrift_spec is not None and fastbinary is not None:
        oprot.trans.write(fastbinary.encode_binary(self, (self.__class__, self.thrift_spec)))
        return
      [...]

    def read(self, iprot):
      if iprot.__class__ == TBinaryProtocol.TBinaryProtocolAccelerated and isinstance(iprot.trans, TTransport.CReadableTransport) and self.thrift_spec is not None and fastbinary is not None:
        fastbinary.decode_binary(self, iprot.trans, (self.__class__, self.thrift_spec))
        return
      [...]

Instantiating the buffer, the protocol, etc. is unnecessary work when we can just do that.

```python
def formula_2018(individu, period, parameters):
```

```py
def _container_is_running(container_name):
    try:
        output = subprocess.check_output(['docker', 'inspect', '--format', '{{.State.Running}}',
                                          container_name]).strip()
    except subprocess.CalledProcessError:
        # This will be raised if the container didn't exist.
        return None
    else:
        if output == 'true':
            return True
        elif output == 'false':
            return False
        else:
            assert False, "Got unexpected value for State.Running (%s)"
```

